class Solution:
    def minMoves(self, nums):
        # simulate by repeatedly counting how many are below the max
        target = max(nums)
        total = 0
        for v in nums:
            steps = 0
            cur = v
            while cur < target:
                cur += 1
                steps += 1
            total += steps
        return total

solutions.python:
class Solution:
    def minMoves(self, nums):
        mx = max(nums)
        return sum(mx - v for v in nums)

